SELECT anomaly_type, COUNT(*)
FROM anomalies
WHERE anomaly_value = (
    SELECT MAX(anomaly_value) FROM anomalies
)
GROUP BY anomaly_type;

SELECT anomalies.anomaly_id, anomalies.anomaly_date, anomalies.anomaly_value, anomalies.anomaly_type, anomalies.anomaly_description, anomalies.anomaly_impact
FROM anomalies
JOIN time_series_data ON anomalies.data_id = time_series_data.data_id;

SELECT f.forecast_accuracy
FROM forecasts f
JOIN time_series_data tsd ON f.data_id = tsd.data_id;

SELECT tsd.data_id, tsd.ds, tsd.yhat, ds.source_name
FROM time_series_data tsd
INNER JOIN data_sources ds ON tsd.source_id = ds.source_id;

SELECT source_name, source_type
FROM data_sources
WHERE source_id IN (
    SELECT DISTINCT source_id
    FROM time_series_data
);
